parameters.jsCode:
// Monta payload para GPT: oportunidades de conteúdo + produtos/serviços a partir dos comentários.
// Entrada: saída do nó "Analisar Estrutura de Conteúdo" (cliente + concorrentes com posts.comentarios_ordenados).

const dados = $input.first().json || {};
const nome = dados.nome_cliente || "";
const nicho = dados.nicho || "";
const handleCliente = dados.handle_cliente || dados.cliente?.handle || "";

function flattenComentarios(nodes, depth, out) {
  const d = depth ?? 0;
  for (const n of nodes || []) {
    if (!n || typeof n !== "object") continue;
    const texto = String(n.texto || "").trim();
    if (texto.length >= 2) {
      out.push({
        texto: texto.slice(0, 500),
        autor: n.comentador_username || null,
        profundidade_resposta: d,
        comentario_foi_respondido_pelo_dono:
          n.comentario_foi_respondido_pelo_dono === true,
      });
    }
    if (Array.isArray(n.respostas) && n.respostas.length) {
      flattenComentarios(n.respostas, d + 1, out);
    }
  }
  return out;
}

function extrairPostsComComentarios(bloco, limitePosts) {
  const posts = Array.isArray(bloco?.posts) ? bloco.posts : [];
  const comComentario = posts.filter(
    (p) => Array.isArray(p.comentarios_ordenados) && p.comentarios_ordenados.length
  );
  comComentario.sort(
    (a, b) => Number(b.engajamento_total || 0) - Number(a.engajamento_total || 0)
  );
  return comComentario.slice(0, limitePosts).map((p) => {
    const flat = [];
    flattenComentarios(p.comentarios_ordenados, 0, flat);
    const maxCom = 45;
    return {
      link_post: p.link_post || "",
      shortCode: p.shortCode || "",
      legenda_resumo: String(p.legenda || "").slice(0, 220),
      curtidas: p.curtidas ?? 0,
      comentarios_contagem: p.comentarios ?? 0,
      comentarios_texto: flat.slice(0, maxCom),
    };
  });
}

const limitePostsPorPerfil = 8;
const cliente = dados.cliente || null;
const concorrentes = dados.concorrentes || [];

const payloadUsuario = {
  contexto: {
    nome_cliente: nome,
    nicho,
    handle_cliente: handleCliente,
  },
  cliente: cliente
    ? {
        handle: cliente.handle,
        posts_com_audience: extrairPostsComComentarios(cliente, limitePostsPorPerfil),
      }
    : null,
  concorrentes: concorrentes.map((c) => ({
    handle: c.handle,
    posts_com_audience: extrairPostsComComentarios(c, limitePostsPorPerfil),
  })),
};

const temAlgum =
  (payloadUsuario.cliente?.posts_com_audience || []).length > 0 ||
  payloadUsuario.concorrentes.some(
    (x) => (x.posts_com_audience || []).length > 0
  );

if (!temAlgum) {
  return [
    {
      json: {
        _sem_comentarios_texto: true,
        gpt_payload_comentarios: {
          model: "gpt-4.1-mini",
          messages: [
            {
              role: "system",
              content:
                'Retorne um único JSON com chave raiz "insights_comentarios". Sem comentários na entrada: indique em resumo_geral que não havia textos (apenas contagens ou API vazia).',
            },
            {
              role: "user",
              content: JSON.stringify(
                {
                  aviso:
                    "Nenhum comentário textual foi encontrado nos posts (comentarios_ordenados vazio).",
                  contexto: payloadUsuario.contexto,
                },
                null,
                2
              ),
            },
          ],
          max_tokens: 1200,
          temperature: 0.25,
        },
      },
    },
  ];
}

const systemPrompt = `Você é estrategista de conteúdo e monetização para Instagram. Analise comentários REAIS por post.

REGRAS:
1. EVIDÊNCIA TEXTUAL: Cite frases reais dos comentários para justificar cada insight (ex: "Comentário: 'quando você abre mentoria?'").
2. SEPARAÇÃO CLARA: Diferencie insights do CLIENTE vs CONCORRENTES — o que o público pede de cada um.
3. SINAIS DE COMPRA: Destaque qualquer comentário com intenção comercial explícita.
4. PADRÕES DE ENGAJAMENTO: Identifique qual tipo de conteúdo gerou mais comentários com mais palavras (mais engajados).

Saída: JSON único válido (sem markdown), chave raiz "insights_comentarios":
{
  "insights_comentarios": {
    "resumo_geral": "Síntese de 100 palavras com os achados mais valiosos",
    "top_autores_que_mais_comentam": [
      { "username": "@...", "qtd_comentarios": 0, "media_palavras": 0, "intencao_detectada": "comprador|fa|critico|neutro" }
    ],
    "temas_audiencia": [
      { "tema": "", "frequencia_estimada": "alta|media|baixa", "exemplo_falas": ["frase real do comentário"] }
    ],
    "oportunidades_conteudo_cliente": [
      { "titulo_ideia": "Título pronto para usar como gancho", "formato": "Reel|Carrossel|Stories", "justificativa": "Baseado no comentário X do post Y", "inspirado_em_concorrentes_handles": ["@handle"] }
    ],
    "oportunidades_produto_servico": [
      { "oferta": "Nome da oferta", "publico": "Para quem", "cta_sugerido": "Texto exato do CTA", "sinal_de_compra": "Frase do comentário que indicou esta oportunidade" }
    ],
    "conteudo_que_mais_gerou_comentarios_ricos": [
      { "handle": "@...", "legenda_resumo": "...", "por_que_funcionou": "Análise do padrão" }
    ],
    "comparativo_cliente_vs_concorrentes": "O que o público pede do cliente que os concorrentes já entregam — e o que o cliente tem que eles não têm",
    "proximos_passos": ["Ação específica 1", "Ação específica 2", "Ação específica 3"]
  }
}`;

let userStr = JSON.stringify(payloadUsuario, null, 2);
const maxChars = 95000;
if (userStr.length > maxChars) {
  userStr = userStr.slice(0, maxChars) + "\n... [truncado por tamanho]";
}

return [
  {
    json: {
      gpt_payload_comentarios: {
        model: "gpt-4.1",
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userStr },
        ],
        max_tokens: 6000,
        temperature: 0.35,
      },
    },
  },
];

// Reanexa a saída do "Analisar Estrutura de Conteúdo" + JSON parseado do GPT de comentários.

const base = $('Analisar Estrutura de Conteúdo1').first().json;
const gpt = $input.first().json;

function safeParse(txt) {
  if (!txt || typeof txt !== "string") return null;
  try {
    return JSON.parse(txt);
  } catch (_) {}
  const m = txt.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) {
    try {
      return JSON.parse(m[1]);
    } catch (_) {}
  }
  const start = txt.indexOf("{");
  const end = txt.lastIndexOf("}");
  if (start >= 0 && end > start) {
    try {
      return JSON.parse(txt.slice(start, end + 1));
    } catch (_) {}
  }
  return null;
}

const raw = gpt?.choices?.[0]?.message?.content || "";
const parsed = safeParse(raw);
const insights = parsed?.insights_comentarios ?? parsed;

return [
  {
    json: {
      ...base,
      insights_comentarios_auditoria: insights || null,
      gpt_comentarios_raw: raw,
      gpt_comentarios_parse_ok: Boolean(insights),
      tokens_comentarios: gpt?.usage?.total_tokens ?? null,
    },
  },
];

// Valida payload de entrada { nome_cliente, nicho, handle_cliente, concorrentes[] }
const raw  = $input.first().json;
const body = raw.body ?? raw;
const cellcli = raw.headers.cellphone;
const nome_cliente   = (body.nome_cliente   || '').trim();
const nicho          = (body.nicho          || '').trim();
const handle_cliente = (body.handle_cliente || '').replace('@', '').trim();
const concorrentes   = (body.concorrentes   || [])
  .map(h => String(h).replace('@', '').trim())
  .filter(Boolean);

if (!nome_cliente || !nicho || !handle_cliente || concorrentes.length === 0) {
  throw new Error('Payload incompleto. Envie: nome_cliente, nicho, handle_cliente, concorrentes[].');
}

const todos_handles = [handle_cliente, ...concorrentes];

return [{ json: {
  nome_cliente,
  nicho,
  handle_cliente,
  concorrentes,
  todos_handles,
  iniciado_em: new Date().toISOString(),
  cellcli,
}}];

// Normaliza posts (até 20 por handle) num shape leve e agrupa por tipo
const rapItems  = $input.all();
const origItems = $('Expandir Handles').all();

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function normalizarTipoOrigem(tipo) {
  const t = String(tipo || '').toLowerCase().trim();
  if (t === 'cliente' || t === 'client' || t === 'principal' || t === 'perfil_cliente') {
    return 'cliente';
  }
  return 'concorrente';
}

function extrairPosts(resp) {
  if (Array.isArray(resp?.result?.edges)) return resp.result.edges.map(e => e.node ?? e).filter(Boolean);
  if (Array.isArray(resp?.edges))         return resp.edges.map(e => e.node ?? e).filter(Boolean);
  if (Array.isArray(resp?.data?.edges))   return resp.data.edges.map(e => e.node ?? e).filter(Boolean);
  if (Array.isArray(resp?.items))         return resp.items;
  if (Array.isArray(resp?.result?.items)) return resp.result.items;
  if (Array.isArray(resp?.data?.items))   return resp.data.items;
  if (Array.isArray(resp?.medias))        return resp.medias;
  if (Array.isArray(resp?.result?.medias))return resp.result.medias;
  if (Array.isArray(resp?.data?.medias))  return resp.data.medias;

  const user = resp?.user ?? resp?.data?.user ?? resp?.result?.user ?? {};
  if (Array.isArray(user.edge_owner_to_timeline_media?.edges)) {
    return user.edge_owner_to_timeline_media.edges.map(e => e.node ?? e).filter(Boolean);
  }
  return [];
}

function getShortCode(node) { return node.shortcode ?? node.code ?? node.short_code ?? ''; }

function getLegenda(node) {
  const legenda =
    node.edge_media_to_caption?.edges?.[0]?.node?.text ??
    node.caption?.text ?? node.caption?.caption ?? node.caption ?? '';
  return typeof legenda === 'string' ? legenda : '';
}

function isVideo(node) {
  return Boolean(
    node.is_video === true ||
    node.media_type === 2 ||
    node.product_type === 'clips' ||
    node.video_url ||
    Array.isArray(node.video_versions)
  );
}

function isCarrossel(node) {
  return Boolean(
    node.edge_sidecar_to_children ||
    Array.isArray(node.carousel_media) ||
    node.carousel_media_count
  );
}

function getTipoConteudo(node) {
  if (isVideo(node)) return 'video';
  if (isCarrossel(node)) return 'carrossel';
  return 'imagem';
}

function getVideoUrl(node) {
  return node.video_url ?? node.video_versions?.[0]?.url ?? null;
}

function getImagemUrl(node) {
  return (
    node.display_url ??
    node.thumbnail_url ??
    node.image_versions2?.candidates?.[0]?.url ??
    node.image_versions?.items?.[0]?.url ??
    node.carousel_media?.[0]?.image_versions2?.candidates?.[0]?.url ??
    null
  );
}

function getTimestamp(node) {
  return node.taken_at ?? node.taken_at_timestamp ?? null;
}

function normalizarPost(node) {
  const shortCode = getShortCode(node);
  const tipoConteudo = getTipoConteudo(node);
  const curtidas = toNumber(
    node.edge_liked_by?.count ?? node.like_count ?? node.likes_count ?? node.fb_like_count ?? 0
  );
  const comentarios = toNumber(
    node.edge_media_to_comment?.count ?? node.comment_count ?? node.comments_count ?? node.fb_comment_count ?? 0
  );
  const views = toNumber(
    node.video_view_count ?? node.play_count ?? node.view_count ?? node.ig_play_count ?? 0
  );
  const videoUrl = getVideoUrl(node);
  const imagemUrl = getImagemUrl(node);
  const ts = getTimestamp(node);

  return {
    link_post: shortCode ? `https://www.instagram.com/p/${shortCode}/` : '',
    shortCode: shortCode,
    tipo_conteudo: tipoConteudo,
    formato_midia: tipoConteudo === 'video' ? 'video' : 'imagem',
    link_midia: tipoConteudo === 'video' ? videoUrl : imagemUrl,
    thumb: tipoConteudo === 'video' ? imagemUrl : null,
    legenda: getLegenda(node),
    curtidas,
    comentarios,
    views,
    engajamento_total: curtidas + comentarios,
    publicado_em: ts ? new Date(ts * 1000).toISOString() : null,
  };
}

const grupos = rapItems.map((rapItem, idx) => {
  const orig = origItems[idx]?.json || {};
  const resp = rapItem.json || {};
  const origemTipo = normalizarTipoOrigem(orig.tipo);
  const handle = orig.handle;
  const posts = extrairPosts(resp)
    .slice(0, 20)
    .map(normalizarPost)
    .filter(p => p.link_post || p.link_midia || p.legenda);
  return { handle, tipo: origemTipo, total_posts: posts.length, posts };
});

const cliente      = grupos.find(g => g.tipo === 'cliente') || null;
const concorrentes = grupos.filter(g => g.tipo === 'concorrente');

return [{ json: { cliente, concorrentes } }];

// Mescla Perfis + Posts em um JSON único { cliente, concorrentes }, match por handle
const perfilItems = $('Normalizar Perfis-standBy').all();
const postsItems  = $('getComentarios1').all();
const postsFallback = $('Normalizar Posts1').all();
const ctx = $('Expandir Handles').first().json;

function toNumber(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function normHandle(h) {
  return String(h || '').trim().toLowerCase().replace(/^@/, '');
}

function indexarPostsPorHandle(grupoPosts) {
  const mapa = new Map();
  if (!grupoPosts) return mapa;
  if (grupoPosts.cliente?.handle) mapa.set(normHandle(grupoPosts.cliente.handle), grupoPosts.cliente);
  for (const c of grupoPosts.concorrentes || []) {
    if (c?.handle) mapa.set(normHandle(c.handle), c);
  }
  return mapa;
}

function calcularMetricas(posts, seguidores) {
  const lista = Array.isArray(posts) ? posts : [];
  const total = lista.length;
  if (total === 0) {
    return {
      total_posts_analisados: 0,
      taxa_engajamento: '0.00',
      media_curtidas: 0,
      media_comentarios: 0,
      media_views: 0,
      mix_formatos: { reels_pct: 0, carrossel_pct: 0, foto_pct: 0 },
      top_posts: [],
      posts_video: [],
      ultimos_15_posts: [],
    };
  }
  const somaCurtidas    = lista.reduce((s, p) => s + toNumber(p.curtidas), 0);
  const somaComentarios = lista.reduce((s, p) => s + toNumber(p.comentarios), 0);
  const somaViews       = lista.reduce((s, p) => s + toNumber(p.views), 0);
  const somaEng         = lista.reduce((s, p) => s + toNumber(p.engajamento_total ?? (p.curtidas + p.comentarios)), 0);

  const segurosSeguidores = toNumber(seguidores) || 1;
  const taxa_engajamento = ((somaEng / total / segurosSeguidores) * 100).toFixed(2);

  const qtdVideo     = lista.filter(p => p.tipo_conteudo === 'video').length;
  const qtdCarrossel = lista.filter(p => p.tipo_conteudo === 'carrossel').length;
  const qtdFoto      = lista.filter(p => p.tipo_conteudo === 'imagem' || p.tipo_conteudo === 'foto').length;

  return {
    total_posts_analisados: total,
    taxa_engajamento,
    media_curtidas:    Math.round(somaCurtidas    / total),
    media_comentarios: Math.round(somaComentarios / total),
    media_views:       Math.round(somaViews       / total),
    mix_formatos: {
      reels_pct:     Math.round((qtdVideo     / total) * 100),
      carrossel_pct: Math.round((qtdCarrossel / total) * 100),
      foto_pct:      Math.round((qtdFoto      / total) * 100),
    },
    top_posts: [...lista].sort((a, b) => toNumber(b.engajamento_total) - toNumber(a.engajamento_total)).slice(0, 5),
    posts_video: lista.filter(p => p.tipo_conteudo === 'video' && p.link_midia),
    ultimos_15_posts: lista.slice(0, 15),
  };
}

function mesclar(blocoPerfil, entradaPosts) {
  const posts       = entradaPosts?.posts ?? [];
  const total_posts = entradaPosts?.total_posts ?? posts.length;
  const seguidores  = blocoPerfil?.perfil?.metricas?.seguidores ?? 0;
  return {
    handle:     blocoPerfil?.handle ?? entradaPosts?.handle ?? '',
    tipo:       blocoPerfil?.tipo   ?? entradaPosts?.tipo   ?? '',
    encontrado: Boolean(blocoPerfil?.encontrado),
    perfil:     blocoPerfil?.perfil ?? null,
    total_posts,
    posts,
    metricas_posts: calcularMetricas(posts, seguidores),
  };
}

const grupoPerfil = perfilItems[0]?.json || {};
let grupoPosts  = postsItems[0]?.json || postsFallback[0]?.json || {};
if (!grupoPosts?.cliente || !Array.isArray(grupoPosts.cliente.posts)) {
  grupoPosts = postsFallback[0]?.json || {};
}
const mapaPosts   = indexarPostsPorHandle(grupoPosts);

const clienteMesclado = mesclar(
  grupoPerfil.cliente,
  mapaPosts.get(normHandle(grupoPerfil?.cliente?.handle)) || grupoPosts.cliente || {},
);

const concorrentesMesclados = (grupoPerfil.concorrentes || []).map(c =>
  mesclar(c, mapaPosts.get(normHandle(c?.handle)) || {}),
);

return [{ json: {
  nome_cliente:         ctx.nome_cliente,
  nicho:                ctx.nicho,
  handle_cliente:       ctx.handle_cliente,
  concorrentes_handles: ctx.concorrentes,
  todos_handles:        ctx.todos_handles,
  iniciado_em:          ctx.iniciado_em,
  cliente:              clienteMesclado,
  concorrentes:         concorrentesMesclados,
}}];

// Extrai padrões estruturais de conteúdo: ganchos, hashtags, CTAs, pilares,
// comprimento de legenda, mentions recorrentes e score comparativo cliente vs concorrentes
const dados       = $input.first().json;
const cliente     = dados.cliente;
const concorrentes = dados.concorrentes || [];


function extrairHashtags(texto) {
  const m = String(texto || '').match(/#[A-Za-z0-9_ÀÁÂÃÄÇÉÊÍÓÔÕÚàáâãäçéêíóôõú]+/g);
  return m || [];
}

function extrairMentions(texto) {
  const m = String(texto || '').match(/@[A-Za-z0-9_.]+/g);
  return m || [];
}

function primeiraLinha(texto) {
  return String(texto || '').split('\n')[0].slice(0, 140);
}

function inferirCta(texto) {
  const t = String(texto || '').toLowerCase();
  const padroes = [
    { tag: 'comenta_palavra',     re: /comenta\s+[\"'a-z0-9çãéõíá]+/i },
    { tag: 'dm_direct',            re: /(chama no direct|no direct|me manda|me chama)/i },
    { tag: 'salva_post',           re: /(salva esse post|salva aqui|salva pra)/i },
    { tag: 'link_bio',             re: /(link na bio|clica na bio|bio\s*👆)/i },
    { tag: 'marca_amigo',          re: /(marca (aquele|aquela|um|uma)|marque)/i },
    { tag: 'segue_para_mais',      re: /(me segue|segue (a|o)? @|segue pra mais)/i },
    { tag: 'curte_e_compartilha',  re: /(curte e compartilha|compartilha com)/i },
    { tag: 'pergunta_aberta',      re: /\?\s*$/m },
  ];
  const hits = [];
  for (const p of padroes) if (p.re.test(t)) hits.push(p.tag);
  return hits.length ? hits : ['sem_cta_claro'];
}

const STOP = new Set([
  'para','pelo','pela','pelos','pelas','como','mais','menos','esse','essa','essas','esses',
  'isto','isso','esta','este','estas','estes','você','voces','vocês','então','entao',
  'sobre','também','tambem','ainda','aqui','tudo','todas','todos','quando','quanto','porque',
  'onde','tenho','tinha','tenha','tenham','muito','muita','muitas','muitos','foram','estão',
  'estou','minha','minhas','meu','meus','nosso','nossos','nossa','nossas','tanto',
  'agora','mesmo','mesma','mesmos','mesmas','depois','antes','dentro','sempre',
  'nunca','jamais','ontem','hoje','amanhã','amanha','vamos','vamo','bora','fazer',
  'feito','faço','faco','fazendo','falar','falei','falou','quase','todo','toda',
  'pode','podem','posso','temos','tinha','estavam','fosse','seria','seriam',
]);

function clusterizarTemas(posts) {
  const freq = new Map();
  for (const p of posts) {
    const palavras = String(p.legenda || '')
      .toLowerCase()
      .replace(/[#@][\wÀ-ÿ]+/g, ' ')
      .replace(/https?:\/\/\S+/g, ' ')
      .replace(/[^\wÀ-ÿ\s]/g, ' ')
      .split(/\s+/)
      .filter(w => w.length >= 4 && !STOP.has(w));
    for (const w of palavras) freq.set(w, (freq.get(w) || 0) + 1);
  }
  return Array.from(freq.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 15)
    .map(([palavra, f]) => ({ palavra, freq: f }));
}

function analisarPerfil(bloco) {
  const posts = bloco?.posts || [];
  const top   = bloco?.metricas_posts?.top_posts || [];
  const todasHashtags = [];
  const todasMentions = [];
  let somaLenTop = 0;
  let somaLenTodos = 0;

  for (const p of posts) {
    todasHashtags.push(...extrairHashtags(p.legenda));
    todasMentions.push(...extrairMentions(p.legenda));
    somaLenTodos += String(p.legenda || '').length;
  }
  for (const p of top) somaLenTop += String(p.legenda || '').length;

  const freqHashtags = new Map();
  for (const h of todasHashtags) {
    const k = h.toLowerCase();
    freqHashtags.set(k, (freqHashtags.get(k) || 0) + 1);
  }
  const freqMentions = new Map();
  for (const m of todasMentions) {
    const k = m.toLowerCase();
    freqMentions.set(k, (freqMentions.get(k) || 0) + 1);
  }

  const ctasTop = {};
  for (const p of top) {
    for (const c of inferirCta(p.legenda)) {
      ctasTop[c] = (ctasTop[c] || 0) + 1;
    }
  }
  const ctaDominante = Object.entries(ctasTop).sort((a, b) => b[1] - a[1])[0]?.[0] || 'sem_cta_claro';

  return {
    handle: bloco?.handle,
    tipo:   bloco?.tipo,
    ganchos_top: top.map(p => ({
      shortcode: (p.link_post || '').split('/p/')[1]?.replace('/', '') || '',
      primeira_linha: primeiraLinha(p.legenda),
