function tabela(headers, rows) {
  if (!Array.isArray(rows) || rows.length === 0) return '_[indisponível]_';
  const head = `| ${headers.join(' | ')} |`;
  const sep  = `| ${headers.map(() => '---').join(' | ')} |`;
