function isForbiddenKey(k) {
  const lower = String(k).toLowerCase();
  if (lower.includes('link_post') || lower.includes('link_midia')) return true;
  if (lower === 'link' || lower.endsWith('_link')) return true;
  if (lower.includes('shortcode')) return true;
  if (lower.includes('thumb')) return true;
  if (lower === 'url' || lower.endsWith('_url')) return true;
  if (lower.includes('permalink')) return true;
  if (lower.includes('media_url') || lower.includes('video_url') || lower.includes('display_url')) return true;
  if (lower.includes('cdn')) return true;
  return false;
}

function stripUrls(s) {
  return String(s || '')
    .replace(/https?:\/\/[^\s]+/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function sanitizarValor(v) {
  if (v === null || v === undefined) return v;
  if (typeof v === 'string') return stripUrls(v);
  if (Array.isArray(v)) return v.map(sanitizarValor);
  if (typeof v === 'object') return sanitizarObjeto(v);
  return v;
}

function sanitizarObjeto(obj) {
  if (!obj || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(sanitizarValor);
  const out = {};
  for (const [k, val] of Object.entries(obj)) {
    if (isForbiddenKey(k)) continue;
    out[k] = sanitizarValor(val);
  }
  return out;
}

/** plano_diretor pode vir como objeto ou string JSON (edge cases). */
function extrairObjetoPlanoDiretor(raw) {
  if (!raw) return {};
  if (typeof raw === 'object' && !Array.isArray(raw)) return raw;
  if (typeof raw === 'string') {
    try {
      return JSON.parse(raw);
    } catch (_) {
      const m = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (m) {
        try {
          return JSON.parse(m[1]);
        } catch (_) {}
      }
    }
  }
  return {};
}

