// ── Helpers ──────────────────────────────────────────────────────────────────

function tryParseJson(s) {
  if (typeof s !== "string") return null;
  try { return JSON.parse(s); } catch { return null; }
}

function contarPalavras(texto) {
  if (!texto || typeof texto !== "string") return 0;
  const t = texto.trim();
  return t ? t.split(/\s+/).length : 0;
}

function normHandle(h) {
  return String(h || "").trim().toLowerCase().replace(/^@/, "");
}

function mesmoAutor(a, b) {
  if (!a || !b) return false;
  return normHandle(a) === normHandle(b);
}

// ── Desembrulha a resposta do instagram-looter2 ───────────────────────────────
// O endpoint /post retorna o shortcode_media diretamente ou aninhado em graphql/data

function desembrulhar(raw) {
  if (raw == null) return null;
  if (typeof raw === "string") {
    const p = tryParseJson(raw);
    return p ? desembrulhar(p) : null;
  }
  if (Array.isArray(raw)) {
    for (const item of raw) {
      const u = desembrulhar(item);
      if (u?.edge_media_to_parent_comment?.edges) return u;
    }
    return null;
  }
  if (typeof raw !== "object") return null;

  // Direto no objeto raiz
  if (raw.edge_media_to_parent_comment?.edges) return raw;

  // Aninhado em graphql.shortcode_media
  if (raw.graphql?.shortcode_media?.edge_media_to_parent_comment?.edges)
    return raw.graphql.shortcode_media;

  // Aninhado em data ou data.shortcode_media
  const d = raw.data;
  if (d) {
    if (d.edge_media_to_parent_comment?.edges) return d;
    if (d.shortcode_media?.edge_media_to_parent_comment?.edges) return d.shortcode_media;
    const nested = desembrulhar(d);
    if (nested) return nested;
  }

  // Outros envelopes comuns
  for (const key of ["media", "item", "payload", "result"]) {
    const v = raw[key];
    if (v && typeof v === "object" && !Array.isArray(v)) {
      const nested = desembrulhar(v);
      if (nested) return nested;
    }
  }

  // items[0]
  if (Array.isArray(raw.items) && raw.items[0]) {
    const nested = desembrulhar(raw.items[0]);
    if (nested) return nested;
  }

  // body
  if (raw.body != null) {
    const b = typeof raw.body === "string" ? tryParseJson(raw.body) : raw.body;
    const nested = desembrulhar(b);
    if (nested) return nested;
  }

  return null;
}

// ── Constrói árvore de comentários ───────────────────────────────────────────

function nodeParaItem(node) {
  if (!node) return null;
  const texto = node.text ?? "";
  const owner = node.owner ?? {};
  const item = {
    id:                    node.id,
    texto,
    palavras:              contarPalavras(texto),
    comentador_username:   owner.username ?? null,
    comentador_id:         owner.id       ?? null,
    is_verified:           Boolean(owner.is_verified),
    created_at:            node.created_at ?? null,
    respostas:             [],
  };
  for (const e of (node.edge_threaded_comments?.edges || [])) {
    const filho = nodeParaItem(e?.node);
    if (filho) item.respostas.push(filho);
  }
  return item;
}

function donoNaSubarvore(n, dono) {
  if (!n || !dono) return false;
  if (mesmoAutor(n.comentador_username, dono)) return true;
  return (n.respostas || []).some(r => donoNaSubarvore(r, dono));
}

function marcarRespostasDoDono(itens, dono) {
  if (!Array.isArray(itens)) return;
  function walk(n) {
    if (!n) return;
    (n.respostas || []).forEach(walk);
    if (mesmoAutor(n.comentador_username, dono)) {
      delete n.comentario_foi_respondido_pelo_dono;
      return;
    }
    n.comentario_foi_respondido_pelo_dono = Boolean(
      (n.respostas || []).some(f => donoNaSubarvore(f, dono))
    );
  }
  itens.forEach(walk);
}

function ordenar(lista) {
  return [...lista].sort((a, b) => {
    if (b.palavras !== a.palavras) return b.palavras - a.palavras;
    return (b.is_verified ? 1 : 0) - (a.is_verified ? 1 : 0);
  });
}

function ordenarArvore(itens) {
  if (!itens?.length) return itens;
  const s = ordenar(itens);
  for (const it of s)
    if (it.respostas?.length) it.respostas = ordenarArvore(it.respostas);
  return s;
}

function extrairComentarios(rawResp, handleDono) {
  const graph = desembrulhar(rawResp);
  if (!graph?.edge_media_to_parent_comment?.edges) return [];
  const dono = handleDono ?? graph.owner?.username ?? null;
  const lista = [];
  for (const e of graph.edge_media_to_parent_comment.edges) {
    const t = nodeParaItem(e?.node);
    if (t) lista.push(t);
  }
  marcarRespostasDoDono(lista, dono);
  return ordenarArvore(lista);
}

