async function enriquecerBloco(bloco) {
  if (!bloco || !Array.isArray(bloco.posts)) return bloco;
  const handleDono = normHandle(bloco.handle || bloco.perfil?.username) || null;
  const meta = { handle: bloco.handle ?? null, pedidos: 0, ok: 0, erros: [] };

  for (let i = 0; i < bloco.posts.length; i++) {
    const p = bloco.posts[i];
    delete p.comentarios_api_erro;

    const url =
      p.link_post ||
      (p.shortCode ? `https://www.instagram.com/p/${p.shortCode}/` : "") ||
      (p.shortcode ? `https://www.instagram.com/p/${p.shortcode}/` : "");

    if (!url || !(Number(p.comentarios) > 0)) {
      p.comentarios_ordenados = [];
      continue;
    }

    meta.pedidos++;
    try {
      const raw = await buscarComentarios(url);
      p.comentarios_ordenados = extrairComentarios(raw, handleDono);
      meta.ok++;
    } catch (e) {
      p.comentarios_ordenados = [];
      p.comentarios_api_erro = String(e?.message || e);
      meta.erros.push({ url, erro: p.comentarios_api_erro });
    }

    if (DELAY_MS && i < bloco.posts.length - 1) await sleep(DELAY_MS);
  }

  bloco._comentarios_meta = meta;
  return bloco;
}

