}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function normalizarTipoOrigem(tipo) {
  const t = String(tipo || "")
    .toLowerCase()
    .trim();
  if (
    t === "cliente" ||
    t === "client" ||
    t === "principal" ||
    t === "perfil_cliente"
  ) {
    return "cliente";
  }
  return "concorrente";
}

function extrairUsuario(resp) {
  if (resp?.result?.[0]?.user) return resp.result[0].user;
  if (Array.isArray(resp?.result) && resp.result[0]?.user)
    return resp.result[0].user;
  if (resp?.result?.user) return resp.result.user;
  if (resp?.data?.user) return resp.data.user;
  if (resp?.user) return resp.user;
  if (resp?.graphql?.user) return resp.graphql.user;
  return null;
}

function extrairDominio(url) {
  if (!url || typeof url !== "string") return null;
  try {
    const u = new URL(url);
    return u.hostname.replace(/^www\./, "");
  } catch (_) {
    return null;
  }
}

function temUtm(url) {
  if (!url || typeof url !== "string") return false;
  return /[?&](utm_[a-z]+|fbclid|gclid)=/i.test(url);
}

function simplificarBioLinks(bioLinks) {
  if (!Array.isArray(bioLinks)) return [];
  return bioLinks.map((link) => ({
    title: link.title || "",
    url: link.url || "",
    lynx_url: link.lynx_url || "",
    link_type: link.link_type || null,
    is_pinned: Boolean(link.is_pinned),
    is_verified: Boolean(link.is_verified),
  }));
}

function getProfilePicHd(user) {
  return (
    user?.hd_profile_pic_url_info?.url ??
    user?.hd_profile_pic_versions?.slice(-1)?.[0]?.url ??
    user?.profile_pic_url_hd ??
    null
  );
}

function getBiografia(user) {
  return user?.biography ?? user?.biography_with_entities?.raw_text ?? "";
}

function normalizarPerfil(user) {
  if (!user) return null;
  const followers = toNumber(
    user.follower_count ?? user.edge_followed_by?.count ?? 0
  );
  const following = toNumber(
    user.following_count ?? user.edge_follow?.count ?? 0
  );
  const postsCount = toNumber(
    user.media_count ?? user.edge_owner_to_timeline_media?.count ?? 0
  );
  const ratio =
    following > 0 ? Number((followers / following).toFixed(2)) : null;

  const bioLinks = simplificarBioLinks(user.bio_links);
  const externalUrl = user.external_url || "";

  const todosUrls = [
    externalUrl,
    ...bioLinks.map((l) => l.url),
    ...bioLinks.map((l) => l.lynx_url),
  ].filter(Boolean);
  const dominiosSet = new Set(
    todosUrls
      .map(extrairDominio)
      .filter(Boolean)
      .filter((d) => d !== "l.instagram.com")
  );

  const usaUtm =
    bioLinks.some((l) => temUtm(l.url) || temUtm(l.lynx_url)) ||
    temUtm(externalUrl);

  return {
    id: user.pk_id ?? user.id ?? "",
    username: user.username ?? "",
    full_name: user.full_name ?? "",
    biografia: getBiografia(user),
    foto_perfil: user.profile_pic_url ?? "",
    foto_perfil_hd: getProfilePicHd(user),
    is_verificado: Boolean(user.is_verified),
    is_privado: Boolean(user.is_private),
    is_business: Boolean(user.is_business),
    account_type: user.account_type ?? null,
    categoria: user.category || user.account_category || "",
    metricas: {
      seguidores: followers,
      seguindo: following,
      qtd_posts: postsCount,
      qtd_reels: toNumber(user.total_clips_count ?? 0),
      seguidores_em_comum: toNumber(user.mutual_followers_count ?? 0),
      ratio_seguidor_seguindo: ratio,
      tem_destaques: Boolean(user.has_highlight_reels),
    },
    contato: {
      email: user.public_email ?? "",
      telefone: user.public_phone_number ?? "",
      telefone_contato: user.contact_phone_number ?? "",
      cidade: user.city_name ?? "",
      endereco: user.address_street ?? "",
    },
    links: {
      site_externo: externalUrl,
      threads: user.threads_profile_glyph_url ?? "",
      bio_links: bioLinks,
      dominios_bio: Array.from(dominiosSet),
      tem_utm: usaUtm,
      qtd_links: bioLinks.length + (externalUrl ? 1 : 0),
    },
    pronomes: Array.isArray(user.pronouns) ? user.pronouns : [],
  };
}

async function montarGrupo(rapItem, orig) {
  const origemTipo = normalizarTipoOrigem(orig.tipo);
  const handle = orig.handle;
  let resp = rapItem.json || {};
  let user = extrairUsuario(resp);
  let perfil = normalizarPerfil(user);
  let extrasUsadas = 0;

  while (!perfil && extrasUsadas < RETRIES_EXTRA) {
    await sleep(DELAY_MS);
    extrasUsadas += 1;
    try {
      resp = await buscarUserInfo(handle);
      user = extrairUsuario(resp);
      perfil = normalizarPerfil(user);
    } catch (_) {
      /* mantém perfil null; próxima iteração tenta de novo */
    }
  }

  return {
    handle,
    tipo: origemTipo,
    encontrado: Boolean(perfil),
    perfil,
    tentativas_extras_perfil: extrasUsadas,
  };
}

async function run() {
  const rapItems = $input.all();
  const origItems = allOrigExpandir();

  const grupos = await Promise.all(
    rapItems.map((rapItem, idx) =>
      montarGrupo(rapItem, origItems[idx]?.json || {})
    )
  );

  const cliente = grupos.find((g) => g.tipo === "cliente") || null;
  const concorrentes = grupos.filter((g) => g.tipo === "concorrente");

  const handles_nao_encontrados = grupos
    .filter((g) => !g.encontrado)
    .map((g) => ({
      handle: g.handle,
      tipo: g.tipo,
      tentativas_extras_perfil: g.tentativas_extras_perfil,
    }));

  return [
    {
      json: {
        cliente,
        concorrentes,
        handles_nao_encontrados,
      },
    },
  ];
}

return await run();
